import React, { useState } from 'react';
import './styles.css';

export default function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (username === 'varshini' && password === 'varshu') {
      alert('Login Successful');
    } else {
      alert('Invalid Username or Password');
    }
  };

  return (
    <div className="container">
      <div className="left-panel">
        <div className="logo">AI Resume <span>Screening System</span></div>
        <h1>AI-Powered Resume <span>Screening</span> Made Simple</h1>
        <p>Analyze, rank and hire the best candidates faster with the power of AI.</p>
        <div className="illustration">💻</div>
      </div>

      <div className="right-panel">
        <div className="login-card">
          <div className="lock">🔒</div>
          <h2>Admin Login</h2>
          <p>Welcome back! Please login to continue.</p>

          <form onSubmit={handleSubmit}>
            <label>Email Address</label>
            <input
              type="text"
              placeholder="Enter your email"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
            />

            <label>Password</label>
            <input
              type="password"
              placeholder="Enter your password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />

            <button type="submit">Login</button>
          </form>

          <div className="footer">© 2024 AI Resume Screening System. All rights reserved.</div>
        </div>
      </div>
    </div>
  );
}
